-- 验证插入结果
SELECT 
    COUNT(*) as total_rolls,
    COUNT(DISTINCT batch_no) as batch_count,
    SUM(area) as total_area_sqm,
    AVG(area) as avg_area_per_roll,
    MIN(area) as min_area,
    MAX(area) as max_area
FROM film_stock_detail 
WHERE stock_id = 1 AND status = 'available';
